package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithTrailingDelimiter() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withTrailingDelimiter();

        // Then
        assertTrue(result.getTrailingDelimiter());
    }

    @Test
    public void testWithTrailingDelimiter_false() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT.withTrailingDelimiter(false);

        // When
        CSVFormat result = csvFormat.withTrailingDelimiter();

        // Then
        assertFalse(result.getTrailingDelimiter());
    }

    @Test
    public void testWithTrailingDelimiter_privateMethodInvocation() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        Class<?> csvFormatClass = csvFormat.getClass();
        Method privateMethod = csvFormatClass.getDeclaredMethod("isLineBreak", char.class);
        privateMethod.setAccessible(true);

        // When
        boolean result = (boolean) privateMethod.invoke(csvFormat, 'c');

        // Then
        assertTrue(result);
    }
}
